import React, { useState } from "react";
import {
  Container, Paper, Typography, TextField, Button, Alert, Box
} from "@mui/material";
import { useNavigate } from "react-router-dom";
import { signupRider, uploadRiderDocs } from "../services/api";

export default function RiderRegister() {
  const navigate = useNavigate();
  const [formData, setFormData] = useState({ fullName: "", email: "", mobile: "" });
  const [docs, setDocs] = useState({ aadharFront: null, aadharBack: null, license: null });
  const [error, setError] = useState(""); const [success, setSuccess] = useState("");
  const [loading, setLoading] = useState(false);

  const handleFileChange = (e) => setDocs((p) => ({ ...p, [e.target.name]: e.target.files[0] }));

  const handleSubmit = async (e) => { /* signup + upload docs */ };

  return (
    <Container maxWidth="sm" sx={{ display: "flex", alignItems: "center", height: "100vh" }}>
      <Paper sx={{ p: 5, borderRadius: 4, boxShadow: 5, width: "100%", textAlign: "center" }}>
        <Typography variant="h4" sx={{ fontWeight: "bold", mb: 1, color: "primary.main" }}>
          Rider Signup
        </Typography>
        <Typography variant="body2" sx={{ mb: 3, color: "text.secondary" }}>
          Create your rider account and upload documents
        </Typography>

        {error && <Alert severity="error" sx={{ mb: 2 }}>{error}</Alert>}
        {success && <Alert severity="success" sx={{ mb: 2 }}>{success}</Alert>}

        <form onSubmit={handleSubmit}>
          <TextField fullWidth label="Full Name" name="fullName" margin="normal" />
          <TextField fullWidth label="Email" type="email" name="email" margin="normal" />
          <TextField fullWidth label="Mobile Number" name="mobile" margin="normal" />

          <Typography variant="h6" sx={{ mt: 3, mb: 1 }}>Upload Documents</Typography>
          <Box sx={{ display: "grid", gap: 2 }}>
            {["aadharFront", "aadharBack", "license"].map((doc) => (
              <Button key={doc} variant="outlined" component="label">
                Upload {doc}
                <input type="file" hidden name={doc} onChange={handleFileChange} />
              </Button>
            ))}
          </Box>

          <Button fullWidth type="submit" sx={{ mt: 3, py: 1.3 }} variant="contained" disabled={loading}>
            {loading ? "Submitting..." : "Sign Up"}
          </Button>
        </form>

        <Typography sx={{ mt: 3 }}>
          Already have an account?{" "}
          <Button onClick={() => navigate("/rider-login")} sx={{ fontWeight: "bold" }}>Login</Button>
        </Typography>
      </Paper>
    </Container>
  );
}
